#!/bin/bash
set -e

echo "=== Step 1: Starting Neo4j ==="
docker compose up -d neo4j

echo "=== Step 2: Waiting for Neo4j to be healthy ==="
for i in $(seq 1 10); do
  echo "Attempt $i/10..."
  if docker compose exec neo4j cypher-shell -u neo4j -p changeme123 "RETURN 1" 2>/dev/null; then
    echo "Neo4j is ready!"
    break
  fi
  if [ "$i" -eq 10 ]; then
    echo "ERROR: Neo4j did not become ready after 10 attempts"
    exit 1
  fi
  sleep 5
done

echo "=== Step 3: Cleaning existing data ==="
curl -s -X POST "http://localhost:7474/db/neo4j/tx/commit" \
  -u "neo4j:changeme123" \
  -H "Content-Type: application/json" \
  -d '{"statements": [{"statement": "MATCH (n) WHERE n:Product OR n:Part OR n:Symptom OR n:Cause OR n:Solution DETACH DELETE n"}]}'
echo ""

